import React from 'react';
import { Film } from 'lucide-react';

const MovieCard = ({ movie, delay }) => {
  // Gracefully handle strings (old backend) and objects (new backend)
  const title = typeof movie === 'object' ? movie.title : movie;
  const poster = typeof movie === 'object' ? movie.poster_path : null;
  const overview = typeof movie === 'object' ? movie.overview : null;

  return (
    <div 
      className="movie-card"
      style={{
        animation: `fadeInUp 0.6s ease-out ${delay}s forwards`,
        opacity: 0,
        transform: 'translateY(20px)',
        padding: '1rem'
      }}
    >
      {poster && !poster.includes("Error") ? (
        <div 
          className="movie-poster" 
          style={{ 
            backgroundImage: `url(${poster})`, 
            height: '250px', 
            backgroundSize: 'cover', 
            backgroundPosition: 'center', 
            borderRadius: '0.75rem',
            width: '100%',
            marginBottom: '0.5rem'
          }}
        ></div>
      ) : (
        <div className="movie-icon-wrapper" style={{ height: '250px', width: '100%', background: 'rgba(59, 130, 246, 0.1)', borderRadius: '0.75rem', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Film size={48} color="rgba(59, 130, 246, 0.5)" />
        </div>
      )}
      <div className="movie-info">
        <h3 className="movie-title" style={{ fontSize: '1.2rem', marginBottom: '0.5rem' }}>{title}</h3>
        {overview && (
          <p className="movie-overview" style={{ fontSize: '0.9rem', color: 'var(--text-secondary)', display: '-webkit-box', WebkitLineClamp: 3, WebkitBoxOrient: 'vertical', overflow: 'hidden' }}>
            {overview}
          </p>
        )}
      </div>
    </div>
  );
};

export default MovieCard;
